arrayPipelines.data:
[
  {
    $match: {
      "workflow_name": "SALES_TO_POST_SALES_WORKFLOW"
    }
  },
  {
    $match: {{ workflow_logs_filter_js.getMatchQuery() }}
  },
  { $sort: { started_at: -1 } },
  {
    $project: {
      _id: 0,
      created_at: 1,
      event_subject: 1,
      client_id: 1,
      workflow_name: 1,
      attendee_emails: 1,
      customer_name: "$processed_emails.email_content.customer_name",
      call_name: "$processed_emails.email_content.call_name",
      call_date: "$processed_emails.email_content.call_date",

      prospect_attendees_text: {
        $let: {
          vars: {
            paAll: {
              $reduce: {
                input: {
                  $map: {
                    input: { $ifNull: ["$processed_emails.email_content.stakeholders_points", []] },
                    as: "sp",
                    in: { $ifNull: ["$$sp.stakeholders", []] }
                  }
                },
                initialValue: [],
                in: { $concatArrays: ["$$value", "$$this"] }
              }
            }
          },
          in: {
            $reduce: {
              input: "$$paAll",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this.attendee"
                ]
              }
            }
          }
        }
      },

      objectives_text: {
        $let: {
          vars: { obs: { $ifNull: ["$processed_emails.email_content.business_scope_context.objectives", []] } },
          in: {
            $reduce: {
              input: "$$obs",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      pain_points_text: {
        $let: {
          vars: { pts: { $ifNull: ["$processed_emails.email_content.business_scope_context.pain_points", []] } },
          in: {
            $reduce: {
              input: "$$pts",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      success_metrics_text: {
        $let: {
          vars: { sms: { $ifNull: ["$processed_emails.email_content.business_scope_context.success_metrics", []] } },
          in: {
            $reduce: {
              input: "$$sms",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      use_cases_text: {
        $let: {
          vars: { ucs: { $ifNull: ["$processed_emails.email_content.solution_scope_context.use_cases", []] } },
          in: {
            $reduce: {
              input: "$$ucs",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      must_haves_text: {
        $let: {
          vars: { mhs: { $ifNull: ["$processed_emails.email_content.solution_scope_context.must_haves", []] } },
          in: {
            $reduce: {
              input: "$$mhs",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      assumptions_text: {
        $let: {
          vars: { asm: { $ifNull: ["$processed_emails.email_content.solution_scope_context.assumptions", []] } },
          in: {
            $reduce: {
              input: "$$asm",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      systems_text: {
        $let: {
          vars: { sys: { $ifNull: ["$processed_emails.email_content.technical_environment_context.systems_and_integrations", []] } },
          in: {
            $reduce: {
              input: {
                $map: {
                  input: "$$sys",
                  as: "s",
                  in: {
                    $concat: [
                      { $ifNull: ["$$s.system", ""] },
                      " (", { $ifNull: ["$$s.integration_method", ""] }, ")"
                    ]
                  }
                }
              },
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      technical_notes_text: {
        $let: {
          vars: { tns: { $ifNull: ["$processed_emails.email_content.technical_environment_context.technical_notes", []] } },
          in: {
            $reduce: {
              input: "$$tns",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      primary_contact_name: "$processed_emails.email_content.plan_cadence_context.primary_contact.name",
      primary_contact_role: "$processed_emails.email_content.plan_cadence_context.primary_contact.role",

      next_steps_text: {
        $let: {
          vars: { nss: { $ifNull: ["$processed_emails.email_content.plan_cadence_context.immediate_next_steps", []] } },
          in: {
            $reduce: {
              input: {
                $map: {
                  input: "$$nss",
                  as: "ns",
                  in: {
                    $concat: [
                      { $ifNull: ["$$ns.timeframe", ""] },
                      ": ",
                      {
                        $reduce: {
                          input: { $ifNull: ["$$ns.actions", []] },
                          initialValue: "",
                          in: {
                            $concat: [
                              { $cond: [{ $eq: ["$$value", ""] }, "", ", "] },
                              "$$this.action",
                              " (", { $ifNull: ["$$this.owner", ""] }, ")"
                            ]
                          }
                        }
                      }
                    ]
                  }
                }
              },
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      critical_open_items_text: {
        $let: {
          vars: { coi: { $ifNull: ["$processed_emails.email_content.plan_cadence_context.critical_open_items", []] } },
          in: {
            $reduce: {
              input: "$$coi",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      commitments_fulfilled_text: {
        $let: {
          vars: { cf: { $ifNull: ["$processed_emails.email_content.plan_cadence_context.commitments.fulfilled", []] } },
          in: {
            $reduce: {
              input: "$$cf",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },

      commitments_pending_text: {
        $let: {
          vars: { cp: { $ifNull: ["$processed_emails.email_content.plan_cadence_context.commitments.pending", []] } },
          in: {
            $reduce: {
              input: "$$cp",
              initialValue: "",
              in: {
                $concat: [
                  { $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
                  "$$this"
                ]
              }
            }
          }
        }
      },
		"tx_consumed": 1
    }
  }
]

